sql:
SELECT COUNT(pedon_id) 
FROM soil_pedons 
WHERE collector_id = 1 AND analysis_status = 'in progress';

SELECT taxonname
FROM soil_pedons
WHERE pedon_type = 'undefined observation';

external_knowledge:
- "undefined observation" refers to soil samples where the type of pedon observation is not clearly defined or categorized;
- "loamy-skeletal" is a class of particle size that indicates a mix of loamy and skeletal (coarse) particles;
- "40th and 39th southern parallels" refers to the latitude range between -40.0000 and -39.0000.

sql:
SELECT taxonname
FROM taxonomic_classifications
WHERE taxon_kind = 'taxadjunct';

SELECT COUNT(*) 
FROM taxonomic_subgroups 
WHERE description LIKE '%Description%';

external_knowledge:
- 'Typic' refers to a specific type of pedon observation;
- 'sandy-skeletal' refers to a class of particle size characterized by a high proportion of sand and skeletal material;
- 'deep' refers to a depth class indicating a significant depth of the soil sample.

sql:
SELECT COUNT(DISTINCT taxonname) AS Total_Count
FROM soil_pedons
WHERE pedon_type IN ('Typic', 'Lithic');

SELECT taxon_kind, COUNT(pedon_id) AS total_pedons 
FROM soil_pedons 
GROUP BY taxon_kind;

SELECT taxonname
FROM soil_pedons
WHERE depth > 40 AND part_size_class = 'sandy-skeletal';

